#!/bin/bash
set -euo pipefail
ENV_FILE=/opt/robodynamics/ai-tutor/tutor-api/.env
if [ -f "$ENV_FILE" ]; then
  if grep -q '^AI_TUTOR_TEMPLATE_API_URL=' "$ENV_FILE"; then
    sed -i '"'"'s#^AI_TUTOR_TEMPLATE_API_URL=.*#AI_TUTOR_TEMPLATE_API_URL=http://127.0.0.1:8080/api/ai-tutor/course-template#'"'"' "$ENV_FILE"
  else
    echo '"'"'AI_TUTOR_TEMPLATE_API_URL=http://127.0.0.1:8080/api/ai-tutor/course-template'"'"' >> "$ENV_FILE"
  fi
fi
cat <<B64 | base64 -d > /opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py

B64
chown tomcat:tomcat /opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py || true
chmod 644 /opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py
systemctl restart rd-ai-tutor-api
sleep 2
echo "API=$(systemctl is-active rd-ai-tutor-api || true)"
